import types

@types.coroutine
def _yield_to_loop():
    """Raw generator-based coroutine: yields None once, then returns."""
    result = yield  # suspends; event loop calls .send(value) to resume
    return result

class Future:
    """Simplified asyncio.Future to illustrate __await__."""
    def __init__(self):
        self._result = None
        self._done = False
        self._callbacks = []

    def set_result(self, result):
        self._result = result
        self._done = True
        for cb in self._callbacks:
            cb()

    def __await__(self):
        if not self._done:
            yield self   # yield the Future itself; asyncio uses this to register the callback
        return self._result  # raises StopIteration(result) when done

import asyncio

class Deferred:
    """
    A properly integrated awaitable: wraps an asyncio.Future so the
    event loop knows to resume the coroutine when set_result() is called.
    """

    def __init__(self):
        loop = asyncio.get_event_loop()
        self._future = loop.create_future()

    def resolve(self, value):
        if not self._future.done():
            self._future.set_result(value)

    def __await__(self):
        # Delegate entirely to Future's __await__.
        # Future.__await__ yields the future object to the event loop,
        # which registers the coroutine to be resumed on set_result().
        return self._future.__await__()

